  ('elementary-0a2fc18c-moex-00176', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-114-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '有關名目國內生產毛額（nominalGDP），下列敘述何者正確？', '["GDP係衡量某一時點財貨與勞務的市場價值總和", "GDP衡量所有生產過程中投入的要素所得加總，包含中間財貨與勞務的價值", "GDP的衡量包含本國國民在海外的產值，但排除外國國民在本國的產值", "GDP的衡量包含資本折舊準備"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:14+00:00", "source_pdf_sha1": "da6a047c014b", "answer_pdf_sha1": "5b18e8f0e844", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "514", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
